import{_ as t,o as a,c as s,a2 as i}from"./chunks/framework.DTa47_fH.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"SWAO","text":"Sovereign Workload Assessment and Onboarding","tagline":"Audit-grade cloud workload assessments in a single command. No telemetry. No call-home. Your data stays on your machine.","actions":[{"theme":"brand","text":"Quick start (5 min)","link":"/quick-start"},{"theme":"alt","text":"Features & Editions","link":"/features"},{"theme":"alt","text":"How it works","link":"/how-it-works"}]},"features":[{"title":"Five assessment types","details":"Application, Landing Zone, Audit, LLM benchmarking, and Hybrid. Run the full pipeline or target a specific surface."},{"title":"Bring your own LLM","details":"Anthropic Claude, OpenAI, Ollama, or a deterministic stub for offline use. LLM access is included in every edition."},{"title":"Audit-grade traceability","details":"Every signal carries outcome, derivation, assessor identity, false-positive consideration, and timestamp. Defensible against external auditors."},{"title":"HTML publication","details":"A self-contained HTML file with executive, technical, compliance, and auditor views. Works offline, in air-gapped environments, and in email."},{"title":"PowerBI dashboards","details":"Pre-built templates for single-app and portfolio assessments. Star-schema CSV export works with any BI tool."},{"title":"MCP integration","details":"Ask Claude AI questions about your assessment findings in natural language via the Model Context Protocol."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),n={name:"index.md"};function o(r,e,d,l,c,u){return a(),s("div",null,[...e[0]||(e[0]=[i('<h2 id="what-is-swao" tabindex="-1">What is SWAO? <a class="header-anchor" href="#what-is-swao" aria-label="Permalink to &quot;What is SWAO?&quot;">​</a></h2><p>SWAO analyses cloud applications and infrastructure and produces an auditor-grade assessment report. It combines static code analysis, LLM-driven compliance evaluation, and context ingestion from your CMDB and operational documents -- and outputs a full traceability chain from source evidence to compliance verdict.</p><p><strong>File-only on disk.</strong> No telemetry, no hosted endpoint, no call-home. Your source code and assessment data never leave your machine. Bring your own LLM provider.</p><hr><h2 id="assessment-types" tabindex="-1">Assessment types <a class="header-anchor" href="#assessment-types" aria-label="Permalink to &quot;Assessment types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Status</th><th>What you get</th></tr></thead><tbody><tr><td>Application Assessment</td><td>Available</td><td>Full pipeline: inventory, SBOM, data classification, compliance, 7R synthesis</td></tr><tr><td>Landing Zone Assessment</td><td>Available</td><td>Cloud infrastructure fit/gap report against sovereignty requirements</td></tr><tr><td>Audit Assessment</td><td>Coming soon</td><td>Human-led checklist and evidence with deterministic compliance verdict</td></tr><tr><td>LLM Assessment</td><td>Coming soon</td><td>Side-by-side sovereignty benchmarking across multiple LLM providers</td></tr><tr><td>Hybrid Assessment</td><td>Coming soon</td><td>Combined source analysis and consultant audit evidence</td></tr></tbody></table><hr><h2 id="questions-and-licence-requests" tabindex="-1">Questions and licence requests <a class="header-anchor" href="#questions-and-licence-requests" aria-label="Permalink to &quot;Questions and licence requests&quot;">​</a></h2><p>Open a <a href="https://github.com/Accenture/SWAO/discussions" target="_blank" rel="noreferrer">GitHub Discussion</a> or <a href="https://github.com/Accenture/SWAO/issues" target="_blank" rel="noreferrer">raise an issue</a>.</p>',9)])])}const h=t(n,[["render",o]]);export{p as __pageData,h as default};
